-- Unnests an AttributesKey string (generated by GenerateASIStorageAttributesKey / GenerateHUAttributesKey)
-- into its individual parts.
--
-- The AttributesKey format is a '§&§'-separated list of parts, where each part is one of:
--   L (List):   '<M_AttributeValue_ID>'        e.g. '1001234'
--   S (String): '<M_Attribute_ID>=<value>'     e.g. '5000=organic'
--   N (Number): '<M_Attribute_ID>=<value>'     e.g. '5001=42.5'
--   D (Date):   '<M_Attribute_ID>=YYYY-MM-DD'  e.g. '5002=2023-01-15'
--
-- The sentinel '-1002' means AttributesKey.NONE (no storage-relevant attributes); this function returns no rows for it.
--
-- Java equivalent: org.adempiere.mm.attributes.keys.AttributesKeys#toImmutableAttributeSet
-- SQL generator:   GenerateASIStorageAttributesKeyPart

select db_drop_functions('*.UnnestAttributesKey');

CREATE OR REPLACE FUNCTION UnnestAttributesKey(p_AttributesKey text)
    RETURNS TABLE
            (
                m_attribute_id      numeric, -- the owning attribute; for L parts: resolved via M_AttributeValue
                value               text,    -- string representation of the value
                m_attributevalue_id numeric, -- set for L parts only
                part_text           text,    -- raw part string
                part_type           char(1)  -- 'L'=List, 'S'=String, 'N'=Number, 'D'=Date
            )
    LANGUAGE sql
    STABLE -- not IMMUTABLE because L-type parts join M_AttributeValue (a table)
AS
$BODY$
WITH parts AS (SELECT UNNEST(STRING_TO_ARRAY(p_AttributesKey, '§&§')) AS part
               WHERE p_AttributesKey IS NOT NULL
                 AND p_AttributesKey != ''),
     parsed AS (SELECT part,
                       CASE
                           -- List attribute: pure integer (M_AttributeValue_ID)
                           WHEN part ~ '^-?[0-9]+$'
                               THEN 'L'
                           -- Date: M_Attribute_ID=YYYY-MM-DD
                           WHEN part ~ '^[0-9]+=[0-9]{4}-[0-9]{2}-[0-9]{2}$'
                               THEN 'D'
                           -- Number: M_Attribute_ID=<numeric>
                           WHEN part ~ '^[0-9]+=[0-9]+(\.[0-9]+)?$'
                               THEN 'N'
                           -- String: M_Attribute_ID=<anything>
                           WHEN part ~ '^[0-9]+='
                               THEN 'S'
                       END::char(1)                                                                        AS part_type,
                       CASE WHEN part ~ '^[0-9]+=' THEN SPLIT_PART(part, '=', 1)::numeric END              AS attr_id_from_part,
                       CASE WHEN part ~ '^-?[0-9]+$' THEN part::numeric END                                AS attr_value_id,
                       CASE WHEN part ~ '^[0-9]+=' THEN SUBSTRING(part FROM POSITION('=' IN part) + 1) END AS val_text
                FROM parts
                WHERE NOT (part ~ '^-?[0-9]+$' AND part::numeric = -1002) -- exclude AttributesKey.NONE sentinel
     )
SELECT COALESCE(p.attr_id_from_part, av.m_attribute_id) AS m_attribute_id, -- L-type: resolve from M_AttributeValue
       COALESCE(p.val_text, av.value)                   AS value,          -- L-type: use M_AttributeValue.Value
       p.attr_value_id                                  AS m_attributevalue_id,
       p.part                                           AS part_text,
       p.part_type                                      AS part_type
FROM parsed p
         LEFT JOIN m_attributevalue av ON av.m_attributevalue_id = p.attr_value_id
    ;
$BODY$
;

COMMENT ON FUNCTION UnnestAttributesKey(text) IS
    'Unnests an AttributesKey string into its individual attribute parts.

    The AttributesKey is a §&§-separated string generated by GenerateASIStorageAttributesKey (and similar functions).
    Each part represents one storage-relevant attribute value:
      L (List):   M_AttributeValue_ID only — M_Attribute_ID and value resolved via M_AttributeValue join
      S (String): M_Attribute_ID=text-value
      N (Number): M_Attribute_ID=numeric-value
      D (Date):   M_Attribute_ID=YYYY-MM-DD

    Returns empty when input is NULL, empty string, or the NONE sentinel (-1002).

    Java equivalent: org.adempiere.mm.attributes.keys.AttributesKeys#toImmutableAttributeSet'
;
